import React, { Component } from 'react';
import { Collapse, Container, Navbar, NavbarBrand, NavbarToggler, NavItem, NavLink } from 'reactstrap';
import { Link } from 'react-router-dom';
import NavDropdown from 'react-bootstrap/NavDropdown';
import './NavMenu.css';
import { default as User } from '../features/login/User';

export class NavMenu extends Component {
  static displayName = NavMenu.name;

  constructor (props) {
    super(props);

    this.toggleNavbar = this.toggleNavbar.bind(this);
    this.state = {
      collapsed: true
    };
  }

  toggleNavbar () {
    this.setState({
      collapsed: !this.state.collapsed
    });
  }

  bindClick(target){
    if(target === 'LogOut') {
      User.setUserLogin('false');
      console.log(User.isLogin());     
      window.location = "/";
    }
  }

  render () {

    return (
      <header>
        <Navbar className="navbar-expand-sm navbar-toggleable-sm ng-white border-bottom box-shadow mb-3" light>
          <Container>
            <NavbarBrand tag={Link} to="/"><img src="/img/icon/googsu.png" className="logo" alt="logo"/>Kakao API Test</NavbarBrand>
            <NavbarToggler onClick={this.toggleNavbar} className="mr-2" />
            <Collapse className="d-sm-inline-flex flex-sm-row-reverse" isOpen={!this.state.collapsed} navbar>
              <ul className="navbar-nav flex-grow">
                <NavItem>
                  <NavLink tag={Link} className="text-dark" to="/"><img src="/img/icon/home.png" className="logo-menu" alt="Home"/>Home</NavLink>
                </NavItem>
                <NavItem>
                  <NavLink tag={Link} className="text-dark" to="/counter"><img src="/img/icon/counter.png" className="logo-menu" alt="Counter"/>Counter</NavLink>
                </NavItem>
                <NavDropdown title="▤KakaoAPI 3th Party" id="nav-dropdown">
                  <NavDropdown.Item eventKey="4.1" href="/PHPSimplePack.php">PHPSimplePack - kakao REST API</NavDropdown.Item>
                  <NavDropdown.Item eventKey="4.2" href="/JAVASimplePack.php">JAVASimplePack - kakao REST API</NavDropdown.Item>
                  <NavDropdown.Divider />
                  <NavDropdown.Item eventKey="4.3" href="/kakaoJavaScriptSDK.html">JavaScriptWrapper - Kakao JavaScript SDK</NavDropdown.Item> 
                  <NavDropdown.Divider />
                  <NavDropdown.Item eventKey="4.4" href="/map.html">JavaScriptWrapper - Kakao Maps JavaScript SDK</NavDropdown.Item> 
                  <NavDropdown.Divider />
                  <NavDropdown.Item eventKey="4.5" href="https://kakao-tam.tistory.com/19">ASP.NET (framework 4.5) MVC5 : OWIN katana base - kakao login</NavDropdown.Item>
                </NavDropdown>                
              </ul>
            </Collapse>
          </Container>
        </Navbar>
      </header>
    );
  }
}